class Solution:
    def profitableSchemes(self, n, minProfit, group, profit):
        MOD = 10 ** 9 + 7
        m = len(group)
        total = 0
        for mask in range(1 << m):
            members = 0
            gain = 0
            for i in range(m):
                if mask & (1 << i):
                    members += group[i]
                    gain += profit[i]
            if members <= n and gain >= minProfit:
                total += 1
        return total % MOD

