var profitableSchemes = function(n, minProfit, group, profit) {
    const MOD = 1000000007;
    let dp = Array.from({ length: n + 1 }, () => new Array(minProfit + 1).fill(0));
    dp[0][0] = 1;
    for (let c = 0; c < group.length; c++) {
        const g = group[c], p = profit[c];
        const ndp = dp.map(row => row.slice());
        for (let used = n - g; used >= 0; used--) {
            for (let pr = 0; pr <= minProfit; pr++) {
                if (dp[used][pr]) {
                    const npr = Math.min(minProfit, pr + p);
                    ndp[used + g][npr] = (ndp[used + g][npr] + dp[used][pr]) % MOD;
                }
            }
        }
        dp = ndp;
    }
    let total = 0;
    for (let used = 0; used <= n; used++) total = (total + dp[used][minProfit]) % MOD;
    return total;
};
